import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, RotateCcw, Volume2, VolumeX, 
  Shuffle, X, Check, ImageIcon, Filter, Layers
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isShuffled, setIsShuffled] = useState(false);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  // Categories
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort();
  }, [data]);

  // Filtered Data
  const activeData = useMemo(() => {
    let filtered = data;
    if (showImagesOnly) {
      filtered = filtered.filter(q => q.questionImage || q.answerImage);
    }
    if (selectedCategories.length > 0) {
      filtered = filtered.filter(q => selectedCategories.includes(q.category));
    }
    if (isShuffled) {
      return [...filtered].sort(() => Math.random() - 0.5);
    }
    return filtered;
  }, [data, showImagesOnly, selectedCategories, isShuffled]);

  // Reset index when data changes
  useEffect(() => {
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [activeData.length, isShuffled]);

  // Preload next image for performance
  useEffect(() => {
    if (currentIndex < activeData.length - 1) {
        const nextCard = activeData[currentIndex + 1];
        if (nextCard.questionImage) {
            const img = new Image();
            img.src = cleanImageUrl(nextCard.questionImage);
        }
    }
  }, [currentIndex, activeData]);

  const currentCard = activeData[currentIndex];

  const handleNext = () => {
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const handleSpeak = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!currentCard) return;

    if (isSpeaking) {
      cancel();
    } else {
      const text = isFlipped ? currentCard.answerText : currentCard.questionText;
      speak(text, currentCard.id + (isFlipped ? '-a' : '-q'));
    }
  };

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-4">
        <Layers size={48} className="text-slate-300" />
        <h3 className="text-xl font-black text-slate-400">No cards match your filter</h3>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); }}
          className="text-rose-600 font-bold hover:underline"
        >
          Clear filters
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto w-full relative">
      {/* Controls */}
      <div className="flex justify-between items-center px-4 py-4 md:py-6">
        <div className="flex items-center gap-2">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`p-3 rounded-xl border-2 transition-all ${selectedCategories.length > 0 || showImagesOnly ? 'border-rose-500 bg-rose-50 text-rose-600' : 'border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter size={20} />
           </button>
           <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
             {currentIndex + 1} / {activeData.length}
           </span>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => setIsShuffled(!isShuffled)}
             className={`p-3 rounded-xl border-2 transition-all ${isShuffled ? 'border-purple-500 bg-purple-50 text-purple-600' : 'border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Shuffle size={20} />
           </button>
        </div>
      </div>

      {/* Card Area */}
      <div className="flex-1 px-4 pb-4 md:pb-8 flex flex-col justify-center min-h-0">
        <div 
          className="relative w-full h-full perspective-1000 group cursor-pointer"
          onClick={() => setIsFlipped(!isFlipped)}
        >
          <div className={`relative w-full h-full transition-all duration-500 preserve-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* Front */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200 border-2 border-slate-100 p-8 md:p-12 flex flex-col items-center text-center overflow-y-auto custom-scrollbar">
               <span className="absolute top-8 left-8 text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">Query</span>

               <div className="flex-1 flex flex-col items-center justify-center w-full">
                 {currentCard.questionImage && (
                   <div className="mb-8 max-h-[30vh] flex items-center justify-center">
                     <img 
                       src={cleanImageUrl(currentCard.questionImage)} 
                       className="max-h-full max-w-full object-contain rounded-lg" 
                       alt="Question" 
                     />
                   </div>
                 )}

                 <h2 className="text-xl md:text-3xl font-black text-slate-800 leading-tight mb-6" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />

                 {/* Options Display on Front */}
                 {currentCard.options && currentCard.options.length > 0 && (
                    <div className="w-full max-w-2xl grid grid-cols-1 gap-3 mt-4">
                      {currentCard.options.map((opt, i) => (
                        <div key={i} className="flex items-start gap-4 p-4 rounded-xl bg-slate-50 border border-slate-100 text-slate-600 text-left transition-colors hover:bg-slate-100">
                          <span className="w-6 h-6 flex items-center justify-center bg-white rounded-lg border border-slate-200 text-[10px] font-black shrink-0 shadow-sm text-slate-400">
                            {String.fromCharCode(65 + i)}
                          </span>
                          <span className="text-sm font-bold leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                        </div>
                      ))}
                    </div>
                 )}
               </div>

               <div className="absolute bottom-8 right-8">
                 <button onClick={handleSpeak} className="p-4 bg-slate-50 rounded-full text-slate-400 hover:bg-rose-50 hover:text-rose-600 transition-colors">
                   {isSpeaking && speakingId?.endsWith('-q') ? <VolumeX size={24} /> : <Volume2 size={24} />}
                 </button>
               </div>
            </div>

            {/* Back */}
            <div className="absolute inset-0 backface-hidden rotate-y-180 bg-slate-900 rounded-[2.5rem] shadow-2xl p-8 md:p-12 flex flex-col items-center text-center overflow-y-auto custom-scrollbar text-white">
               <span className="absolute top-8 left-8 text-[10px] font-black text-slate-600 uppercase tracking-[0.3em]">Answer</span>

               <div className="flex-1 flex flex-col items-center justify-center w-full">
                 {currentCard.answerImage && (
                   <div className="mb-8 max-h-[30vh] flex items-center justify-center">
                     <img 
                       src={cleanImageUrl(currentCard.answerImage)} 
                       className="max-h-full max-w-full object-contain rounded-lg bg-white/5" 
                       alt="Answer" 
                     />
                   </div>
                 )}

                 <p className="text-xl md:text-3xl font-bold text-emerald-400 leading-relaxed mb-6" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />

                 {/* Options Display on Back with Highlight */}
                 {currentCard.options && currentCard.options.length > 0 && (
                    <div className="w-full max-w-2xl grid grid-cols-1 gap-3 mt-4 mb-6">
                      {currentCard.options.map((opt, i) => {
                        const isCorrect = opt === currentCard.answerText;
                        return (
                          <div key={i} className={`flex items-start gap-4 p-4 rounded-xl border text-left transition-colors ${isCorrect ? 'bg-emerald-500/20 border-emerald-500/50 text-white shadow-lg' : 'bg-white/5 border-white/10 text-slate-500'}`}>
                            <span className={`w-6 h-6 flex items-center justify-center rounded-lg border text-[10px] font-black shrink-0 shadow-sm ${isCorrect ? 'bg-emerald-500 border-emerald-400 text-white' : 'bg-transparent border-white/10 text-slate-600'}`}>
                              {String.fromCharCode(65 + i)}
                            </span>
                            <span className="text-sm font-bold leading-snug flex-1" dangerouslySetInnerHTML={{ __html: opt }} />
                            {isCorrect && <Check className="text-emerald-400 shrink-0" size={18} strokeWidth={3} />}
                          </div>
                        )
                      })}
                    </div>
                 )}

                 {currentCard.explanation && (
                   <div className="w-full max-w-2xl p-5 bg-white/5 rounded-2xl border border-white/10 text-left">
                     <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-2">Clinical Note</span>
                     <p className="text-sm font-medium text-slate-300 leading-relaxed" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               <div className="absolute bottom-8 right-8">
                 <button onClick={handleSpeak} className="p-4 bg-white/10 rounded-full text-slate-400 hover:bg-white/20 hover:text-white transition-colors">
                   {isSpeaking && speakingId?.endsWith('-a') ? <VolumeX size={24} /> : <Volume2 size={24} />}
                 </button>
               </div>
            </div>

          </div>
        </div>
      </div>

      {/* Navigation */}
      <div className="px-8 pb-8 md:pb-12 pt-2 flex justify-center gap-6">
        <button 
          onClick={handlePrev} 
          disabled={currentIndex === 0}
          className="w-16 h-16 rounded-2xl bg-white border-2 border-slate-100 flex items-center justify-center text-slate-400 disabled:opacity-30 hover:border-slate-300 hover:text-slate-600 transition-all shadow-sm"
        >
          <ArrowLeft size={24} strokeWidth={3} />
        </button>

        <button 
          onClick={() => setIsFlipped(!isFlipped)} 
          className="h-16 px-10 rounded-2xl bg-rose-600 text-white font-black uppercase tracking-widest text-xs hover:bg-rose-700 transition-all shadow-xl shadow-rose-200 flex items-center gap-3"
        >
          <RotateCcw size={18} /> Flip Card
        </button>

        <button 
          onClick={handleNext} 
          disabled={currentIndex === activeData.length - 1}
          className="w-16 h-16 rounded-2xl bg-white border-2 border-slate-100 flex items-center justify-center text-slate-400 disabled:opacity-30 hover:border-slate-300 hover:text-slate-600 transition-all shadow-sm"
        >
          <ArrowRight size={24} strokeWidth={3} />
        </button>
      </div>

      {/* Filter Modal */}
      {isFilterOpen && (
        <div className="fixed inset-0 z-[250] animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md" onClick={() => setIsFilterOpen(false)}></div>
          <div className="absolute bottom-0 left-0 right-0 bg-white rounded-t-[3rem] p-8 md:p-10 max-h-[85vh] overflow-y-auto custom-scrollbar animate-in slide-in-from-bottom duration-500 shadow-3xl border-t border-rose-100 pb-safe">
             <div className="flex justify-between items-center mb-8 md:mb-10 pb-6 border-b border-slate-100">
                <h3 className="font-black uppercase text-sm text-slate-800 tracking-widest flex items-center gap-2">
                  <div className="w-1.5 h-6 bg-rose-600 rounded-full"></div> System Filters
                </h3>
                <button onClick={() => setIsFilterOpen(false)} className="p-4 bg-rose-50 rounded-2xl text-rose-600 transition-colors hover:bg-rose-100"><X size={24} /></button>
             </div>

             <div className="space-y-8 md:space-y-10">
                <button onClick={() => setShowImagesOnly(!showImagesOnly)} className={`w-full p-6 rounded-[2rem] font-black uppercase text-xs tracking-widest flex items-center justify-between transition-all border-2 ${showImagesOnly ? 'bg-rose-600 text-white border-rose-600 shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                  <span>Clinical Visuals Only</span> <ImageIcon size={20} />
                </button>

                <div className="space-y-4">
                   <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] px-2 flex items-center gap-2">Anatomical Subsets <div className="h-px flex-1 bg-slate-100"></div></h4>
                   <div className="grid gap-3">
                      {categories.map(cat => (
                        <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`w-full text-left p-5 rounded-2xl text-[11px] font-bold uppercase transition-all flex items-center justify-between border-2 ${selectedCategories.includes(cat) ? 'bg-rose-50 border-rose-500 text-rose-700 shadow-sm' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'}`}>
                          <span className="truncate pr-4">{cat}</span> 
                          {selectedCategories.includes(cat) && <Check size={16} strokeWidth={4} />}
                        </button>
                      ))}
                   </div>
                </div>

                <button onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setIsFilterOpen(false); }} className="w-full py-6 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest mt-6 shadow-xl hover:bg-rose-600 transition-colors">Clear All Filters</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, RotateCcw, Volume2, VolumeX, 
  Shuffle, X, Check, ImageIcon, Filter, Layers, 
  ArrowLeftRight, Eye, EyeOff
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isShuffled, setIsShuffled] = useState(false);
  const [isReversed, setIsReversed] = useState(false); // New: Reverse Q/A
  const [showOptions, setShowOptions] = useState(true); // New: Toggle Options

  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  // Categories
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort();
  }, [data]);

  // Filtered Data
  const activeData = useMemo(() => {
    let filtered = data;
    if (showImagesOnly) {
      filtered = filtered.filter(q => q.questionImage || q.answerImage);
    }
    if (selectedCategories.length > 0) {
      filtered = filtered.filter(q => selectedCategories.includes(q.category));
    }
    if (isShuffled) {
      return [...filtered].sort(() => Math.random() - 0.5);
    }
    return filtered;
  }, [data, showImagesOnly, selectedCategories, isShuffled]);

  // Reset index when data changes
  useEffect(() => {
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [activeData.length, isShuffled]);

  const currentCard = activeData[currentIndex];

  // Determine content based on Reversal State
  const frontContent = isReversed ? {
    label: 'Answer',
    text: currentCard?.answerText,
    image: currentCard?.answerImage,
    isQuestion: false
  } : {
    label: 'Query',
    text: currentCard?.questionText,
    image: currentCard?.questionImage,
    isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Query',
    text: currentCard?.questionText,
    image: currentCard?.questionImage,
    isQuestion: true
  } : {
    label: 'Answer',
    text: currentCard?.answerText,
    image: currentCard?.answerImage,
    isQuestion: false
  };

  const handleNext = () => {
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) {
      cancel();
    } else {
      speak(text, currentCard.id + suffix);
    }
  };

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-4">
        <Layers size={48} className="text-slate-300" />
        <h3 className="text-xl font-black text-slate-400">No cards match your filter</h3>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); }}
          className="text-rose-600 font-bold hover:underline"
        >
          Clear filters
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto w-full relative">
      {/* Controls */}
      <div className="flex justify-between items-center px-4 py-4 md:py-6">
        <div className="flex items-center gap-2">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`p-3 rounded-xl border-2 transition-all ${selectedCategories.length > 0 || showImagesOnly ? 'border-rose-500 bg-rose-50 text-rose-600' : 'border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter size={20} />
           </button>
           <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
             {currentIndex + 1} / {activeData.length}
