                 {/* Options Display on Back (If standard mode) */}
                 {!isReversed && showOptions && currentCard.options && currentCard.options.length > 0 && (
                    <div className="w-full max-w-2xl grid grid-cols-1 gap-3 mt-4 mb-6">
