                 <h2 className={`text-xl md:text-3xl font-black leading-tight mb-6 ${isReversed ? 'text-emerald-600' : 'text-slate-800'}`} dangerouslySetInnerHTML={{ __html: frontContent.text || '' }} />

                 {/* Explanation on Front if it's the Answer side */}
                 {!frontContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-5 bg-emerald-50 rounded-2xl border border-emerald-100 text-left mt-4 animate-in fade-in slide-in-from-bottom-2">
